// Shared helpers used by every page.
// All data lives under ./data/*.json and is generated by scripts/update_stats.py.

export const DATA_PATH = "data";

export async function loadJSON(name) {
  const res = await fetch(`${DATA_PATH}/${name}?t=${Date.now()}`);
  if (!res.ok) throw new Error(`Failed to load ${name}: ${res.status}`);
  return res.json();
}

export function $(sel, root = document) { return root.querySelector(sel); }
export function $$(sel, root = document) { return Array.from(root.querySelectorAll(sel)); }

export function el(tag, attrs, ...children) {
  const node = document.createElement(tag);
  for (const [k, v] of Object.entries(attrs || {})) {
    if (v === null || v === undefined || v === false) continue;
    if (k === "class") node.className = v;
    else if (k === "dataset") Object.assign(node.dataset, v);
    else if (k.startsWith("on") && typeof v === "function") node.addEventListener(k.slice(2), v);
    else if (v === true) node.setAttribute(k, "");
    else node.setAttribute(k, v);
  }
  for (const c of children.flat()) {
    if (c === null || c === undefined || c === false) continue;
    node.append(c.nodeType ? c : document.createTextNode(String(c)));
  }
  return node;
}

export function fmt(n, digits = 1) {
  if (n === null || n === undefined || Number.isNaN(n)) return "–";
  return Number(n).toLocaleString(undefined, {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  });
}

export function fmtInt(n) {
  if (n === null || n === undefined) return "–";
  return Number(n).toLocaleString();
}

export function fmtPct(v, digits = 1) {
  if (v === null || v === undefined || Number.isNaN(v)) return "–";
  return `${(v * 100).toFixed(digits)}%`;
}

export function relativeTime(iso) {
  if (!iso) return "never";
  const then = new Date(iso).getTime();
  const now = Date.now();
  const s = Math.max(0, Math.floor((now - then) / 1000));
  if (s < 60) return `${s}s ago`;
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return `${d}d ago`;
}

export function renderHeader(activePage) {
  const header = $(".site-header");
  if (!header) return;
  const nav = $(".site-nav", header);
  if (nav) {
    $$(".site-nav a", header).forEach((a) => {
      a.classList.toggle("active", a.dataset.page === activePage);
    });
  }
}

export async function renderUpdated() {
  try {
    const meta = await loadJSON("meta.json");
    const span = $("#updated-at");
    if (span) {
      span.textContent = `Updated ${relativeTime(meta.lastUpdated)}`;
      span.title = new Date(meta.lastUpdated).toLocaleString();
    }
  } catch (e) {
    const span = $("#updated-at");
    if (span) span.textContent = "No data yet";
  }
}

export function medalClass(rank) {
  if (rank === 1) return "rank medal-1";
  if (rank === 2) return "rank medal-2";
  if (rank === 3) return "rank medal-3";
  return "rank";
}

export function activePill(isActive) {
  return el(
    "span",
    { class: `pill ${isActive ? "active" : "eliminated"}` },
    isActive ? "Alive" : "Out"
  );
}

/**
 * Attach click-to-sort behaviour to a <table class="stats"> that already has
 * `data-sort-key` on each <th>. Re-renders tbody using the provided builder
 * whenever the sort changes.
 */
export function makeSortable(table, rows, buildRow, initialKey, initialDir = "desc") {
  const body = table.tBodies[0] || table.appendChild(document.createElement("tbody"));
  let sortKey = initialKey;
  let sortDir = initialDir;

  const headers = $$("thead th[data-sort-key]", table);
  const render = () => {
    headers.forEach((h) => h.classList.remove("sort-asc", "sort-desc"));
    const active = headers.find((h) => h.dataset.sortKey === sortKey);
    if (active) active.classList.add(sortDir === "asc" ? "sort-asc" : "sort-desc");
    const sorted = [...rows].sort((a, b) => {
      const av = a[sortKey];
      const bv = b[sortKey];
      if (typeof av === "string" || typeof bv === "string") {
        const cmp = String(av ?? "").localeCompare(String(bv ?? ""));
        return sortDir === "asc" ? cmp : -cmp;
      }
      const aN = av ?? 0;
      const bN = bv ?? 0;
      return sortDir === "asc" ? aN - bN : bN - aN;
    });
    body.innerHTML = "";
    sorted.forEach((r, i) => body.appendChild(buildRow(r, i)));
  };

  headers.forEach((h) => {
    h.addEventListener("click", () => {
      const key = h.dataset.sortKey;
      if (key === sortKey) {
        sortDir = sortDir === "asc" ? "desc" : "asc";
      } else {
        sortKey = key;
        sortDir = h.dataset.sortDefault || "desc";
      }
      render();
    });
  });
  render();
  return { render, setRows: (r) => { rows = r; render(); } };
}

export function teamBadge(abbr) {
  if (!abbr) return el("span", { class: "pill team muted" }, "—");
  return el("span", { class: "pill team" }, abbr);
}

export function posBadge(pos) {
  if (!pos) return "";
  return el("span", { class: `position-badge ${pos[0] || ""}` }, pos);
}

export function movementBadge(delta) {
  if (!delta || Number.isNaN(delta)) {
    return el("span", { class: "move flat", title: "No change since yesterday" }, "—");
  }
  const up = delta > 0;
  return el(
    "span",
    { class: `move ${up ? "up" : "down"}`, title: `Rank ${up ? "up" : "down"} ${Math.abs(delta)} since yesterday` },
    `${up ? "▲" : "▼"}${Math.abs(delta)}`,
  );
}

export function playerSlug(name) {
  return encodeURIComponent(name);
}
